class ODT {
private:
	struct ODT_Node {
		int l, r;
		mutable int v; // 1 表示黑色，0 表示白色

		// 重载小于号以用于 set 排序
		bool operator<(const ODT_Node& a)const {
			return l < a.l;
		}
	};

	set<ODT_Node> se;

	// ODT 的核心操作：分裂区间
	// 将包含 pos 的区间 [l, r] 分裂为 [l, pos - 1] 和 [pos, r]
	// 返回指向后半段 [pos, r] 的迭代器
	auto split(int pos) {
		auto it = se.lower_bound({ pos, 0, 0 });
		if (it != se.end() and it->l == pos)return it;

		it = prev(it);
		auto [l, r, v] = *it;
		se.erase(it);
		se.insert({ l, pos - 1, v });
		return se.insert({ pos, r, v }).first;
	}

public:
	ODT(int n) {
		se.insert({ 1,n,1 });
	}

	// ODT 的核心操作：区间赋值（推平）
	// 将 [l, r] 区间内的所有点染成白色 (v=0)
	void assign(int& ans, int l, int r) {
		// 必须先 split 右边，再 split 左边，否则迭代器可能失效
		auto itr = split(r + 1);
		auto itl = split(l);

		// 遍历 [itl, itr) 之间的所有区间
		auto it = itl;
		while (it != itr) {
			auto [l, r, v] = *it;

			// 如果当前这一小段是黑色 (v=1)，则减去其长度
			if (v == 1)ans -= (r - l + 1);

			// 删除旧区间，erase 返回下一个元素的迭代器
			it = se.erase(it);
		}

		// 插入新的白色区间
		se.insert({ l, r, 0 });
	}
};

void solve(int CASE)
{
	int n, m; cin >> n >> m;
	int ans = n;
	ODT t(n);
	while (m--) {
		int l, r; cin >> l >> r;
		t.assign(ans, l, r);
		cout << ans << endl;
	}
	return;
}
